// Script Continued Below
function onSubmit() {

    var formAction = g_form.getActionName();
    if (formAction == 'save_member') {
		// if it is a new record, send back to server a different way to create new Organizational user, if necessary
		if(g_form.isNewRecord()){
			var formData = {};

			formData = getFieldData(formData, "discover_office_hierarchy");
			formData = getFieldData(formData, "office_member");

			formData = getFieldData(formData, "can_manage_ou_members");
			formData = getFieldData(formData, "is_office_administrator");
			formData = getFieldData(formData, "has_ou_process_rights");
			formData = getFieldData(formData, "office_task_authority");

			formData = getFieldData(formData, "u_organizational_user");
			formData = getFieldData(formData, "u_organizational_user.u_default_ou");
			formData = getFieldData(formData, "u_organizational_user.is_global_hierarchy_administrator");
			formData = getFieldData(formData, "u_organizational_user.has_personal_template_rights");
			formData = getFieldData(formData, "u_organizational_user.can_manage_global_template");
			formData = getFieldData(formData, "u_organizational_user.can_manage_template_permissions");
			formData = getFieldData(formData, "u_organizational_user.is_task_executive");
			formData = getFieldData(formData, "u_organizational_user.is_task_administrator");
			var ga = new GlideAjax("ClientOrganizationalScripts");
			ga.addParam('sysparm_name', 'saveNewMember');
			ga.addParam('sysparam_formData',JSON.stringify(formData));
			ga.getXML(saveNewMemberReturn, null);

			return false;
		}
// need a way to check if Organizational user record exists
// if the user does not exist, need to create it with the values in the form
// may need to cancel the original submit and submit a differnt action after the call back
	}

	function getFieldData(formData, fieldName){
		var fieldInfo;
		if(g_form.getControl(fieldName)){
			formData[fieldName] = {};
			fieldInfo = formData[fieldName];
			fieldInfo.value = g_form.getValue(fieldName);
			fieldInfo.displayValue = g_form.getDisplayValue(fieldName);
		}
		return formData;
	}

	function saveNewMemberReturn(response) {
		var answer = response.responseXML.documentElement.getAttribute("answer");
		if(answer == 'true'){
			top.window.onbeforeunload = null;
			top.window.onunload = null;
alert("RJ - testing - Last step... need to close modal");
		}
		return answer;
	}

}
